# Final secure version
import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
import json
import os
import requests

# Initialize clients using managed identity
blob_service_client = BlobServiceClient(account_url=os.getenv("AZURE_STORAGE_ACCOUNT_URL"), credential=os.getenv("MANAGED_IDENTITY"))
cosmos_client = CosmosClient(url=os.getenv("COSMOS_DB_ENDPOINT"), credential=os.getenv("MANAGED_IDENTITY"))
event_grid_topic_endpoint = os.getenv("EVENT_GRID_TOPIC_ENDPOINT")
event_grid_key = os.getenv("EVENT_GRID_KEY")

def main(blob: func.InputStream):
    logging.info(f"Processing blob: {blob.name}")

    # Read the blob content
    content = blob.read()
    data = json.loads(content)

    # Validate input data
    if not isinstance(data, dict):
        logging.error("Invalid data format")
        return

    # Process data
    result = process_data(data)

    # Write results to Cosmos DB
    write_to_cosmos_db(result)

    # Send notification via Event Grid
    send_event_grid_notification(result)

def process_data(data):
    return {"processed_data": data}

def write_to_cosmos_db(result):
    database_name = os.getenv("COSMOS_DB_DATABASE_NAME")
    container_name = os.getenv("COSMOS_DB_CONTAINER_NAME")
    database = cosmos_client.get_database_client(database_name)
    container = database.get_container_client(container_name)
    container.upsert_item(result)

def send_event_grid_notification(result):
    event_data = {
        "id": str(result.get("id")),
        "eventType": "FileProcessed",
        "subject": "Blob Storage",
        "eventTime": func.datetime.datetime.utcnow().isoformat(),
        "data": result,
        "dataVersion": "1.0"
    }
    headers = {
        "aeg-sas-key": event_grid_key,
        "Content-Type": "application/json"
    }
    response = requests.post(event_grid_topic_endpoint, headers=headers, json=[event_data])
    response.raise_for_status()